class CustomCalendar extends StatefulWidget {
  @override
  _CustomCalendarState createState() => _CustomCalendarState();
}

class _CustomCalendarState extends State<CustomCalendar> {
  DateTime _currentMonth = DateTime.now();
  DateTime? _selectedDay;
  List<DateTime> _daysWithMeetings = [
    DateTime.now().subtract(const Duration(days: 1)),
    DateTime.now().add(const Duration(days: 2)),
  ];

  static const double inch = 96.0;
  
  @override
  Widget build(BuildContext context) {
    List<DateTime> daysInMonth = _generateDaysForMonth(_currentMonth);

    return Center(
      child: Transform.translate(
        offset: const Offset(10, -140),
        child: SizedBox(
          width: 2.3 * inch,
          height: 3 * inch,
          child: Card(
            shape: RoundedRectangleBorder(
                borderRadius: BorderRadius.circular(12)),
            elevation: 3,
            margin: EdgeInsets.zero,
            child: Padding(
              padding: const EdgeInsets.all(8),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Row(
                    mainAxisAlignment: MainAxisAlignment.spaceBetween,
                    children: [
                      IconButton(
                        icon: const Icon(Icons.chevron_left, size: 18),
                        padding: EdgeInsets.zero,
                        constraints: const BoxConstraints(),
                        onPressed: () {
                          setState(() {
                            _currentMonth = DateTime(
                              _currentMonth.year,
                              _currentMonth.month - 1,
                            );
                          });
                        },
                      ),
                      Text(
                        DateFormat('MMMM yyyy').format(_currentMonth),
                        style: const TextStyle(
                            fontSize: 14, fontWeight: FontWeight.w500),
                      ),
                      IconButton(
                        icon: const Icon(Icons.chevron_right, size: 18),
                        padding: EdgeInsets.zero,
                        constraints: const BoxConstraints(),
                        onPressed: () {
                          setState(() {
                            _currentMonth = DateTime(
                              _currentMonth.year,
                              _currentMonth.month + 1,
                            );
                          });
                        },
                      ),
                    ],
                  ),
                  const SizedBox(height: 6),

                  Row(
                    mainAxisAlignment: MainAxisAlignment.spaceBetween,
                    children: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun']
                        .map((d) => Expanded(
                              child: Center(
                                child: Text(
                                  d,
                                  style: TextStyle(
                                      fontWeight: FontWeight.w500,
                                      fontSize: 10,
                                      color: Colors.grey[600]),
                                ),
                              ),
                            ))
                        .toList(),
                  ),
                  const SizedBox(height: 4),

                  Expanded(
                    child: GridView.builder(
                      padding: EdgeInsets.zero,
                      physics: const NeverScrollableScrollPhysics(),
                      gridDelegate:
                          const SliverGridDelegateWithFixedCrossAxisCount(
                        crossAxisCount: 7,
                        mainAxisSpacing: 2,
                        crossAxisSpacing: 2,
                      ),
                      itemCount: daysInMonth.length,
                      itemBuilder: (context, index) {
                        DateTime day = daysInMonth[index];
                        bool isToday = _isSameDay(day, DateTime.now());
                        bool isSelected =
                            _isSameDay(day, _selectedDay ?? DateTime(2000));
                        bool isOtherMonth = day.month != _currentMonth.month;
                        bool hasMeetings = _daysWithMeetings
                            .any((m) => _isSameDay(m, day));
                        Color bgColor = Colors.transparent;
                        Color textColor = isOtherMonth
                            ? Colors.grey[400]!
                            : Colors.black87;
                        if (hasMeetings) textColor = Colors.white;
                        if (isSelected) {
                          bgColor = Colors.grey[600]!;
                          textColor = Colors.white;
                        }
                        if (isToday) {
                          bgColor = const Color(0xFF1a73e8);
                          textColor = Colors.white;
                        }
                        return GestureDetector(
                          onTap: () {
                            setState(() {
                              _selectedDay = day;
                            });
                          },
                          child: Container(
                            decoration: BoxDecoration(
                              color: bgColor,
                              shape: BoxShape.circle,
                            ),
                            child: Center(
                              child: Text(
                                '${day.day}',
                                style: TextStyle(
                                    fontSize: 10, color: textColor),
                              ),
                            ),
                          ),
                        );
                      },
                    ),
                  ),
                  const SizedBox(height: 8),

                  Row(
                    mainAxisAlignment: MainAxisAlignment.spaceBetween,
                    children: [
                      Text(
                        "Today's Meetings",
                        style: TextStyle(
                            fontWeight: FontWeight.w500,
                            fontSize: 12,
                            color: Colors.grey[800]),
                      ),
                      ElevatedButton(
                        onPressed: () {},
                        style: ElevatedButton.styleFrom(
                          backgroundColor: const Color(0xFF1a73e8),
                          padding: const EdgeInsets.symmetric(
                              horizontal: 8, vertical: 4),
                          shape: RoundedRectangleBorder(
                              borderRadius: BorderRadius.circular(20)),
                        ),
                        child: const Text(
                          "+ Add Meeting",
                          style:
                              TextStyle(fontSize: 10, color: Colors.white),
                        ),
                      ),
                    ],
                  ),
                  const SizedBox(height: 4),

                  const Center(
                    child: Text(
                      "No meetings scheduled.",
                      style: TextStyle(
                          fontSize: 10, color: Colors.grey),
                    ),
                  ),
                ],
              ),
            ),
          ),
        ),
      ),
    );
  }

  List<DateTime> _generateDaysForMonth(DateTime month) {
    final firstDayOfMonth = DateTime(month.year, month.month, 1);
    final firstWeekday = (firstDayOfMonth.weekday + 6) % 7;
    final daysBefore = firstWeekday;

    final lastDayOfMonth =
        DateTime(month.year, month.month + 1, 0).day;
    final totalDays = daysBefore + lastDayOfMonth;
    final weeks = (totalDays / 7).ceil();
    final daysAfter = weeks * 7 - totalDays;

    List<DateTime> days = [];
    for (int i = 0; i < daysBefore; i++) {
      days.add(firstDayOfMonth.subtract(Duration(days: daysBefore - i)));
    }
    for (int i = 0; i < lastDayOfMonth; i++) {
      days.add(DateTime(month.year, month.month, i + 1));
    }
    for (int i = 0; i < daysAfter; i++) {
      days.add(DateTime(month.year, month.month + 1, i + 1));
    }
    return days;
  }

  bool _isSameDay(DateTime a, DateTime b) {
    return a.year == b.year && a.month == b.month && a.day == b.day;
  }
}

class CountCacheService {
  static final CountCacheService _instance = CountCacheService._internal();
  factory CountCacheService() => _instance;
  CountCacheService._internal();

  int? _buyerCount;
  int? _craftsmanCount;
  int? _businessPartnerCount;
  int? _kycPendingCount;
  int? _adminCount;
  int? _merchantCount;
  int? _keyUserCount;
  int? _userCount;
  int? _craftmanCount;
  int? _workOrderCount;
  int? _purchaseOrderCount;
  int? _productCount;
  int? _designCount;
  int? _catalogueCount;
  int? _financeCount;
  DateTime? _lastFetchTime;
  
  static const Duration cacheDuration = Duration(seconds: 30);
  
  bool get isCacheValid {
    if (_lastFetchTime == null) return false;
    return DateTime.now().difference(_lastFetchTime!) < cacheDuration;
  }
  
  void updateCounts({
    int? buyerCount,
    int? craftsmanCount,
    int? businessPartnerCount,
    int? kycPendingCount,
    int? adminCount,
    int? merchantCount,
    int? keyUserCount,
    int? userCount,
    int? craftmanCount,
    int? workOrderCount,
    int? purchaseOrderCount,
    int? productCount,
    int? designCount,
    int? catalogueCount,
    int? financeCount,
  }) {
    if (buyerCount != null) _buyerCount = buyerCount;
    if (craftsmanCount != null) _craftsmanCount = craftsmanCount;
    if (businessPartnerCount != null) _businessPartnerCount = businessPartnerCount;
    if (kycPendingCount != null) _kycPendingCount = kycPendingCount;
    if (adminCount != null) _adminCount = adminCount;
    if (merchantCount != null) _merchantCount = merchantCount;
    if (keyUserCount != null) _keyUserCount = keyUserCount;
    if (userCount != null) _userCount = userCount;
    if (craftmanCount != null) _craftmanCount = craftmanCount;
    if (workOrderCount != null) _workOrderCount = workOrderCount;
    if (purchaseOrderCount != null) _purchaseOrderCount = purchaseOrderCount;
    if (productCount != null) _productCount = productCount;
    if (designCount != null) _designCount = designCount;
    if (catalogueCount != null) _catalogueCount = catalogueCount;
    if (financeCount != null) _financeCount = financeCount;
    _lastFetchTime = DateTime.now();
  }
  
  int? get buyerCount => _buyerCount;
  int? get craftsmanCount => _craftsmanCount;
  int? get businessPartnerCount => _businessPartnerCount;
  int? get kycPendingCount => _kycPendingCount;
  int? get adminCount => _adminCount;
  int? get merchantCount => _merchantCount;
  int? get keyUserCount => _keyUserCount;
  int? get userCount => _userCount;
  int? get craftmanCount => _craftmanCount;
  int? get workOrderCount => _workOrderCount;
  int? get purchaseOrderCount => _purchaseOrderCount;
  int? get productCount => _productCount;
  int? get designCount => _designCount;
  int? get catalogueCount => _catalogueCount;
  int? get financeCount => _financeCount;
  
  void clearCache() {
    _buyerCount = null;
    _craftsmanCount = null;
    _businessPartnerCount = null;
    _kycPendingCount = null;
    _adminCount = null;
    _merchantCount = null;
    _keyUserCount = null;
    _userCount = null;
    _craftmanCount = null;
    _workOrderCount = null;
    _purchaseOrderCount = null;
    _productCount = null;
    _designCount = null;
    _catalogueCount = null;
    _financeCount = null;
    _lastFetchTime = null;
  }
}

class DashboardApiService {
  static String get baseUrl => ApiConfig.baseUrl;
  
  static Future<int> fetchCount(String url) async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final token = prefs.getString('token');
      
      if (token == null || token.isEmpty) {
        print('No token available for $url');
        return 0;
      }
      
      final fullUrl = url.startsWith('http') ? url : '$baseUrl$url';
      
      final response = await http.get(
        Uri.parse(fullUrl),
        headers: {
          'Authorization': 'Token $token',
          'Content-Type': 'application/json',
        },
      ).timeout(const Duration(seconds: 50));
      
      if (response.statusCode == 200) {
        final data = json.decode(response.body);
        
        if (data is Map<String, dynamic>) {
          if (data.containsKey('count')) {
            return data['count'] ?? 0;
          } else if (data.containsKey('results') && data['results'] is List) {
            if (data.containsKey('count')) {
              return data['count'] ?? 0;
            }
            return (data['results'] as List).length;
          }
        } else if (data is List) {
          return data.length;
        }
        
        if (data is int) {
          return data;
        }
        
        return 0;
      } else {
        print('Error ${response.statusCode} for $fullUrl: ${response.body}');
      }
      return 0;
    } catch (e) {
      print('Error fetching count from $url: $e');
      return 0;
    }
  }
  
  static Future<Map<String, int>> fetchAllCounts() async {
    final prefs = await SharedPreferences.getInstance();
    final token = prefs.getString('token');
    
    if (token == null || token.isEmpty) {
      print('No token available for fetching counts');
      return _getDefaultCounts();
    }
    
    try {
      final futures = <Future<http.Response?>>[
        _safeGet('/BusinessPartner/BusinessPartner/list/', token),
        _safeGet('/BusinessPartner/BusinessPartner/Buyers/', token),
        _safeGet('/BusinessPartner/BusinessPartner/Craftsmans/', token),
        _safeGet('/BusinessPartner/BusinessPartnerKYC/list/?is_completed=false', token),
        _safeGet('/user/admin/list/', token),
        _safeGet('/user/buyer/list/', token),
        _safeGet('/user/keyuser/list/', token),
        _safeGet('/user/user/list/', token),
        _safeGet('/user/craftsman/list/', token),
        _safeGet('/order/orders/list/', token),
        _safeGet('/PurchaseOrder/PurchaseOrder/list/', token),
        _safeGet('/Products/products/list/', token),
        _safeGet('/Designs/Designs/productslist/', token),
        _safeGet('/Catalogue/Catalogue/lists/', token),
        _safeGet('/BusinessPartner/Finance/list/', token),
      ];
      
      final results = await Future.wait(futures, eagerError: false);
      
      return {
        'businessPartner': _parseCountFromResponse(results[0]),
        'buyer': _parseCountFromResponse(results[1]),
        'craftsman': _parseCountFromResponse(results[2]),
        'kycPending': _parseCountFromResponse(results[3]),
        'admin': _parseCountFromResponse(results[4]),
        'merchant': _parseCountFromResponse(results[5]),
        'keyUser': _parseCountFromResponse(results[6]),
        'user': _parseCountFromResponse(results[7]),
        'craftman': _parseCountFromResponse(results[8]),
        'workOrder': _parseCountFromResponse(results[9]),
        'purchaseOrder': _parseCountFromResponse(results[10]),
        'product': _parseCountFromResponse(results[11]),
        'design': _parseCountFromResponse(results[12]),
        'catalogue': _parseCountFromResponse(results[13]),
        'finance': _parseCountFromResponse(results[14]),
      };
    } catch (e) {
      print('Error fetching all counts: $e');
      return _getDefaultCounts();
    }
  }
  
  static Future<http.Response?> _safeGet(String path, String token) async {
    try {
      final url = '$baseUrl$path';
      print('Fetching: $url');
      return await http.get(
        Uri.parse(url),
        headers: {
          'Authorization': 'Token $token',
          'Content-Type': 'application/json',
        },
      ).timeout(const Duration(seconds: 30));
    } catch (e) {
      print('Safe get error for $path: $e');
      return null;
    }
  }
  
  static int _parseCountFromResponse(http.Response? response) {
    if (response == null || response.statusCode != 200) {
      return 0;
    }
    
    try {
      final data = json.decode(response.body);
      
      if (data is Map<String, dynamic>) {
        if (data.containsKey('count')) {
          final count = data['count'];
          if (count is int) return count;
          if (count is String) return int.tryParse(count) ?? 0;
        } else if (data.containsKey('results') && data['results'] is List) {
          return (data['results'] as List).length;
        }
      } else if (data is List) {
        return data.length;
      }
      
      return 0;
    } catch (e) {
      print('Error parsing response: $e');
      return 0;
    }
  }
  
  static Map<String, int> _getDefaultCounts() {
    return {
      'businessPartner': 0,
      'buyer': 0,
      'craftsman': 0,
      'kycPending': 0,
      'admin': 0,
      'merchant': 0,
      'keyUser': 0,
      'user': 0,
      'craftman': 0,
      'workOrder': 0,
      'purchaseOrder': 0,
      'product': 0,
      'design': 0,
      'catalogue': 0,
      'finance': 0,
    };
  }
}

class DashboardScreen extends StatefulWidget {
