  String? _errorMessage;
  final authService = AuthService.instance;
  final _cacheService = CountCacheService();

  @override
  void initState() {
    super.initState();
    _loadCountsFast();
  }

  Future<void> _loadCountsFast() async {
    setState(() {
      _isLoading = true;
      _errorMessage = null;
    });
    
    if (_cacheService.isCacheValid) {
      setState(() {
        buyerCount = _cacheService.buyerCount ?? 0;
        craftsmanCount = _cacheService.craftsmanCount ?? 0;
        businessPartnerCount = _cacheService.businessPartnerCount ?? 0;
        kycPendingCount = _cacheService.kycPendingCount ?? 0;
        adminCount = _cacheService.adminCount ?? 0;
        merchantCount = _cacheService.merchantCount ?? 0;
        keyUserCount = _cacheService.keyUserCount ?? 0;
        userCount = _cacheService.userCount ?? 0;
        craftmanCount = _cacheService.craftmanCount ?? 0;
        workOrderCount = _cacheService.workOrderCount ?? 0;
        purchaseOrderCount = _cacheService.purchaseOrderCount ?? 0;
        productCount = _cacheService.productCount ?? 0;
        designCount = _cacheService.designCount ?? 0;
        catalogueCount = _cacheService.catalogueCount ?? 0;
        financeCount = _cacheService.financeCount ?? 0;
        _isLoading = false;
      });
      
      _refreshCountsInBackground();
    } else {
      await _refreshCounts();
    }
  }
  
  Future<void> _refreshCounts() async {
    try {
      final counts = await DashboardApiService.fetchAllCounts();
      
      if (mounted) {
        setState(() {
          buyerCount = counts['buyer'] ?? 0;
          craftsmanCount = counts['craftsman'] ?? 0;
          businessPartnerCount = counts['businessPartner'] ?? 0;
          kycPendingCount = counts['kycPending'] ?? 0;
          adminCount = counts['admin'] ?? 0;
          merchantCount = counts['merchant'] ?? 0;
          keyUserCount = counts['keyUser'] ?? 0;
          userCount = counts['user'] ?? 0;
          craftmanCount = counts['craftman'] ?? 0;
          workOrderCount = counts['workOrder'] ?? 0;
          purchaseOrderCount = counts['purchaseOrder'] ?? 0;
          productCount = counts['product'] ?? 0;
          designCount = counts['design'] ?? 0;
          catalogueCount = counts['catalogue'] ?? 0;
          financeCount = counts['finance'] ?? 0;
          _isLoading = false;
        });
        
        _cacheService.updateCounts(
          buyerCount: buyerCount,
          craftsmanCount: craftsmanCount,
          businessPartnerCount: businessPartnerCount,
          kycPendingCount: kycPendingCount,
          adminCount: adminCount,
          merchantCount: merchantCount,
          keyUserCount: keyUserCount,
          userCount: userCount,
          craftmanCount: craftmanCount,
          workOrderCount: workOrderCount,
          purchaseOrderCount: purchaseOrderCount,
