    try {
      final counts = await DashboardApiService.fetchAllCounts();
      
      if (mounted) {
        setState(() {
          buyerCount = counts['buyer'] ?? buyerCount;
          craftsmanCount = counts['craftsman'] ?? craftsmanCount;
