          kycPendingCount = counts['kycPending'] ?? kycPendingCount;
          adminCount = counts['admin'] ?? adminCount;
          merchantCount = counts['merchant'] ?? merchantCount;
          keyUserCount = counts['keyUser'] ?? keyUserCount;
          userCount = counts['user'] ?? userCount;
          craftmanCount = counts['craftman'] ?? craftmanCount;
          workOrderCount = counts['workOrder'] ?? workOrderCount;
          purchaseOrderCount = counts['purchaseOrder'] ?? purchaseOrderCount;
          productCount = counts['product'] ?? productCount;
          designCount = counts['design'] ?? designCount;
          catalogueCount = counts['catalogue'] ?? catalogueCount;
          financeCount = counts['finance'] ?? financeCount;
        });
        
        _cacheService.updateCounts(
          buyerCount: buyerCount,
          craftsmanCount: craftsmanCount,
          businessPartnerCount: businessPartnerCount,
          kycPendingCount: kycPendingCount,
          adminCount: adminCount,
          merchantCount: merchantCount,
          keyUserCount: keyUserCount,
          userCount: userCount,
          craftmanCount: craftmanCount,
          workOrderCount: workOrderCount,
