                        : SingleChildScrollView(
                            child: Column(
                              children: [
                                _buildDashboardCards(),
                                const SizedBox(height: 5),
                                CustomCalendar(),
                              ],
                            ),
                          ),
                  ),
                ],
              ),
            ),
          ),
        ],
      ),
    );
  }

  String _getDisplayCount(int count) {
    if (_isLoading) return '...';
    return count.toString();
  }

  void _navigateToPage(BuildContext context, Widget page) {
    try {
      Navigator.push(
        context,
        MaterialPageRoute(builder: (_) => page),
      );
    } catch (e) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text('Page not available: $e'),
          backgroundColor: Colors.orange,
        ),
      );
    }
  }

  void _showNotImplementedSnackBar(String message) {
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text(message),
        backgroundColor: Colors.orange,
      ),
    );
  }

  Widget _buildUserInfo() {
    final auth = AuthService.instance;
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 12),
      margin: const EdgeInsets.only(bottom: 16),
      decoration: BoxDecoration(
        border: Border(bottom: BorderSide(color: Colors.grey.shade700)),
      ),
      child: Row(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          CircleAvatar(
            radius: 28,
            backgroundColor: Colors.grey.shade800,
            backgroundImage: auth.profilePicture != null &&
                    auth.profilePicture!.isNotEmpty
                ? NetworkImage(auth.profilePicture!)
                : null,
            child: auth.profilePicture == null ||
                    auth.profilePicture!.isEmpty
                ? const Icon(Icons.person, color: Colors.white, size: 30)
                : null,
          ),

          const SizedBox(width: 12),
          Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Text(
                auth.fullName?.isNotEmpty == true ? auth.fullName! : 'User',
                style: const TextStyle(
                  color: Colors.white,
                  fontSize: 16,
                  fontWeight: FontWeight.bold,
                ),
              ),
              const SizedBox(height: 4),
              Text(
                auth.email?.isNotEmpty == true ? auth.email! : 'No Email',
                style: TextStyle(color: Colors.grey.shade400, fontSize: 14),
              ),
              const SizedBox(height: 4),
              Text(
                auth.role ?? '',
                style: TextStyle(color: Colors.grey.shade400, fontSize: 14),
              ),
              const SizedBox(height: 4),
              Text(
                auth.userCode ?? '',
                style: TextStyle(color: Colors.grey.shade400, fontSize: 14),
              ),
              const SizedBox(height: 6),
              Row(
                children: [
                  Container(
                    width: 8,
                    height: 8,
                    decoration: const BoxDecoration(
                      color: Colors.green,
                      shape: BoxShape.circle,
                    ),
                  ),
                  const SizedBox(width: 6),
                  Text(
                    'Active',
                    style:
                        TextStyle(color: Colors.grey.shade400, fontSize: 13),
                  ),
                ],
              ),
            ],
          ),
        ],
      ),
    );
  }

